    71→/// Main TechBuildingBehavior implementation
    72→#[derive(Debug)]
    73→pub struct TechBuildingBehavior {
    74→    // Base module data
    75→    object: Option<Arc<RwLock<Object>>>,
    76→    module_data: Arc<TechBuildingBehaviorModuleData>,
    77→}
    78→
    79→impl TechBuildingBehavior {
    80→    pub fn new(thing: Arc<RwLock<dyn Thing>>, module_data: Arc<dyn ModuleData>) -> Result<Self, Box<dyn std::error::Error>> {
    81→        let data = module_data.as_any()
    82→            .downcast_ref::<TechBuildingBehaviorModuleData>()
    83→            .ok_or("Invalid module data type")?;
    84→        
    85→        Ok(Self {
    86→            object: None, // Will be set after creation
    87→            module_data: Arc::new(data.clone()),
    88→        })
    89→    }
    90→    
    91→    pub fn set_object(&mut self, object: Arc<RwLock<Object>>) {
    92→        self.object = Some(object);
    93→    }
    94→    
    95→    fn get_object(&self) -> Result<Arc<RwLock<Object>>, Box<dyn std::error::Error>> {
    96→        self.object.clone().ok_or("Object not set".into())
    97→    }
    98→    
    99→    /// Handle capture events (when ownership changes)
   100→    pub fn on_capture(&mut self, old_owner: Option<&dyn Player>, new_owner: Option<&dyn Player>) -> Result<(), Box<dyn std::error::Error>> {
   101→        // Wake up next frame so we can re-evaluate our captured status
   102→        // In the original C++, this would call setWakeFrame(getObject(), UPDATE_SLEEP_NONE)
   103→        // Here we'll ensure the next update() call processes the capture change
   104→        Ok(())
   105→    }
   106→}
   107→
   108→impl UpdateModuleInterface for TechBuildingBehavior {
   109→    fn update(&mut self) -> Result<(), Box<dyn std::error::Error>> {
   110→        let object = self.get_object()?;
   111→        let data = &self.module_data;
   112→        let mut captured = false;
   113→        
   114→        // Update our model condition for the captured status
   115→        {
   116→            let obj_guard = object.read().map_err(|_| "Failed to read object")?;
   117→            let controlling_player = obj_guard.get_controlling_player();
   118→            
   119→            if let Some(player) = controlling_player {
   120→                let player_guard = player.read().map_err(|_| "Failed to read player")?;
   121→                let is_playable_side = player_guard.is_playable_side();
   122→                drop(player_guard);
   123→                drop(obj_guard);
   124→                
   125→                if is_playable_side {
   126→                    let mut obj_guard = object.write().map_err(|_| "Failed to write object")?;
   127→                    obj_guard.set_model_condition_state(MODELCONDITION_CAPTURED)?;
   128→                    drop(obj_guard);
   129→                    captured = true;
   130→                } else {
   131→                    let mut obj_guard = object.write().map_err(|_| "Failed to write object")?;
   132→                    obj_guard.clear_model_condition_state(MODELCONDITION_CAPTURED)?;
   133→                    drop(obj_guard);
   134→                    captured = false;
   135→                }
   136→            } else {
   137→                drop(obj_guard);
   138→                let mut obj_guard = object.write().map_err(|_| "Failed to write object")?;
   139→                obj_guard.clear_model_condition_state(MODELCONDITION_CAPTURED)?;
   140→                drop(obj_guard);
   141→                captured = false;
   142→            }
   143→        }
   144→        
   145→        // If we have a pulse fx, and are owned, sleep only a little while, otherwise sleep forever
   146→        if let Some(pulse_fx) = &data.pulse_fx {
   147→            if data.pulse_fx_rate > 0 && captured {
   148→                // Play the pulse FX
   149→                FXList::do_fx_obj(pulse_fx, &object, None)?;
   150→                return Ok(());
   151→            }
   152→        }
   153→        
   154→        // Now sleep forever
   155→        Ok(())
   156→    }
   157→}
