   159→impl DieModuleInterface for TechBuildingBehavior {
   160→    fn on_die(&mut self, object_id: ObjectID, _damage_info: &DamageInfo) {
   161→        let object = self.get_object().unwrap_or_default();
   162→        
   163→        // Put us on the team of the neutral player so no player has any bonus from us
   164→        {
   165→            let mut obj_guard = object.write().map_err(|_| "Failed to write object").unwrap_or_default();
   166→            obj_guard.clear_model_condition_state(MODELCONDITION_CAPTURED).unwrap_or_default();
   167→            
   168→            // Set to neutral team
   169→            let neutral_player = ThePlayerList::get_neutral_player();
   170→            if let Some(neutral) = neutral_player {
   171→                let neutral_guard = neutral.read().map_err(|_| "Failed to read neutral player").unwrap_or_default();
   172→                let default_team = neutral_guard.get_default_team();
   173→                drop(neutral_guard);
   174→                
   175→                if let Some(team) = default_team {
   176→                    obj_guard.set_team(Some(team)).unwrap_or_default();
   177→                }
   178→            }
   179→            
   180→            drop(obj_guard);
   181→        }
   182→        
   183→        ()
   184→    }
   185→}
   186→
   187→impl BehaviorModuleInterface for TechBuildingBehavior {
   188→    fn get_interface_mask() -> u32 {
   189→        MODULEINTERFACE_UPDATE | MODULEINTERFACE_DIE
   190→    fn update(&mut self) -> Result<(), Box<dyn std::error::Error>> {
   191→        UpdateModuleInterface::update(self)
   192→    }
   193→    
   194→    fn get_module_name(&self) -> &str {
   195→        "TechBuildingBehavior"
   196→    }
   197→    }
   198→    
   199→    fn get_update(&self) -> Option<&dyn UpdateModuleInterface> {
   200→        Some(self)
   201→    }
   202→    
   203→    fn get_die(&self) -> Option<&dyn DieModuleInterface> {
   204→        Some(self)
   205→    }
   206→}
