    37→    BodyModuleInterface, DockUpdateInterface,
    38→    UPDATE_SLEEP_FOREVER, UPDATE_SLEEP_NONE, UPDATE_SLEEP,
    39→    MODULEINTERFACE_UPDATE, MODULEINTERFACE_DAMAGE,
    40→};
