    45→/// Module data for SupplyWarehouseCripplingBehavior
    46→#[derive(Debug, Clone)]
    47→pub struct SupplyWarehouseCripplingBehaviorModuleData {
    48→    /// Time since last damage until I can start to heal
    49→    pub self_heal_suppression: UnsignedInt,
    50→    /// Once I am okay to heal, how often to do so
    51→    pub self_heal_delay: UnsignedInt,
    52→    /// And how much to heal
    53→    pub self_heal_amount: Real,
    54→}
    55→
    56→impl SupplyWarehouseCripplingBehaviorModuleData {
    57→    pub fn new() -> Self {
    58→        Self {
    59→            self_heal_suppression: 0,
    60→            self_heal_delay: 0,
    61→            self_heal_amount: 0.0,
    62→        }
    63→    }
    64→}
    65→
    66→impl Default for SupplyWarehouseCripplingBehaviorModuleData {
    67→    fn default() -> Self {
    68→        Self::new()
    69→    }
    70→}
