    72→/// Main SupplyWarehouseCripplingBehavior implementation
    73→#[derive(Debug)]
    74→pub struct SupplyWarehouseCripplingBehavior {
    75→    // Base module data
    76→    object: Option<Arc<RwLock<Object>>>,
    77→    module_data: Arc<SupplyWarehouseCripplingBehaviorModuleData>,
    78→    
    79→    // State tracking
    80→    healing_suppressed_until_frame: UnsignedInt,
    81→    next_healing_frame: UnsignedInt,
    82→}
    83→
    84→impl SupplyWarehouseCripplingBehavior {
    85→    pub fn new(thing: Arc<RwLock<dyn Thing>>, module_data: Arc<dyn ModuleData>) -> Result<Self, Box<dyn std::error::Error>> {
    86→        let data = module_data.as_any()
    87→            .downcast_ref::<SupplyWarehouseCripplingBehaviorModuleData>()
    88→            .ok_or("Invalid module data type")?;
    89→        
    90→        Ok(Self {
    91→            object: None, // Will be set after creation
    92→            module_data: Arc::new(data.clone()),
    93→            healing_suppressed_until_frame: 0,
    94→            next_healing_frame: 0,
    95→        })
    96→    }
    97→    
    98→    pub fn set_object(&mut self, object: Arc<RwLock<Object>>) {
    99→        self.object = Some(object);
   100→    }
   101→    
   102→    fn get_object(&self) -> Result<Arc<RwLock<Object>>, Box<dyn std::error::Error>> {
   103→        self.object.clone().ok_or("Object not set".into())
   104→    }
   105→    
   106→    /// Reset our ability to heal timer, as we took damage
   107→    fn reset_self_heal_suppression(&mut self) -> Result<(), Box<dyn std::error::Error>> {
   108→        let data = &self.module_data;
   109→        let now = TheGameLogic::get_frame();
   110→        
   111→        self.healing_suppressed_until_frame = now + data.self_heal_suppression;
   112→        self.next_healing_frame = self.healing_suppressed_until_frame;
   113→        
   114→        Ok(())
   115→    }
   116→    
   117→    /// Disable our object (when crippled)
   118→    fn start_crippled_effects(&mut self) -> Result<(), Box<dyn std::error::Error>> {
   119→        let object = self.get_object()?;
   120→        let obj_guard = object.read().map_err(|_| "Failed to read object")?;
   121→        
   122→        if let Some(dock) = obj_guard.get_dock_update_interface() {
   123→            let mut dock_guard = dock.lock().map_err(|_| "Failed to lock dock interface")?;
   124→            dock_guard.set_dock_crippled(true)?;
   125→            drop(dock_guard);
   126→        }
   127→        
   128→        drop(obj_guard);
   129→        Ok(())
   130→    }
   131→    
   132→    /// Enable our object (when healed from crippled state)
   133→    fn stop_crippled_effects(&mut self) -> Result<(), Box<dyn std::error::Error>> {
   134→        let object = self.get_object()?;
   135→        let obj_guard = object.read().map_err(|_| "Failed to read object")?;
   136→        
   137→        if let Some(dock) = obj_guard.get_dock_update_interface() {
   138→            let mut dock_guard = dock.lock().map_err(|_| "Failed to lock dock interface")?;
   139→            dock_guard.set_dock_crippled(false)?;
   140→            drop(dock_guard);
   141→        }
   142→        
   143→        drop(obj_guard);
   144→        Ok(())
   145→    }
   146→}
   147→
   148→impl UpdateModuleInterface for SupplyWarehouseCripplingBehavior {
   149→    fn update(&mut self) -> Result<(), Box<dyn std::error::Error>> {
   150→        // Suppression is handled by sleeping the module, so if we're here, it's time to heal
   151→        let data = &self.module_data;
   152→        let object = self.get_object()?;
   153→        let now = TheGameLogic::get_frame();
   154→        
   155→        self.next_healing_frame = now + data.self_heal_delay;
   156→        
   157→        // Attempt healing
   158→        {
   159→            let mut obj_guard = object.write().map_err(|_| "Failed to write object")?;
   160→            obj_guard.attempt_healing(data.self_heal_amount, None)?;
   161→            drop(obj_guard);
   162→        }
   163→        
   164→        // Check if we're at full health
   165→        let obj_guard = object.read().map_err(|_| "Failed to read object")?;
   166→        let is_at_full_health = if let Some(body) = obj_guard.get_body_module() {
   167→            let body_guard = body.lock().map_err(|_| "Failed to lock body module")?;
   168→            let current_health = body_guard.get_health();
   169→            let max_health = body_guard.get_max_health();
   170→            drop(body_guard);
   171→            current_health >= max_health
   172→        } else {
   173→            false
   174→        };
   175→        drop(obj_guard);
   176→        
   177→        if is_at_full_health {
   178→            // Sleep forever if at full health - can't heal anymore
   179→            return Ok(());
   180→        }
   181→        
   182→        // Delay between heals is also handled by sleeping the module
   183→        Ok(())
   184→    }
   185→}
   186→
   187→impl DamageModuleInterface for SupplyWarehouseCripplingBehavior {
   188→    /// Damage has been dealt, this is an opportunity to react to that damage
   189→    fn on_damage(&mut self, _damage_info: &mut DamageInfo) -> Result<(), Box<dyn std::error::Error>> {
   190→        let now = TheGameLogic::get_frame();
   191→        
   192→        self.reset_self_heal_suppression()?;
   193→        
   194→        // We got hit, time to get up for work after a quick snooze
   195→        let sleep_time = self.healing_suppressed_until_frame.saturating_sub(now);
   196→        
   197→        // Wake up the module to start healing after suppression period
   198→        // Note: In the original C++, this would call setWakeFrame on the object
   199→        // Here we'll return the appropriate sleep time when update() is called
   200→        
   201→        Ok(())
   202→    }
   203→    
   204→    fn on_healing(&mut self, _damage_info: &mut DamageInfo) -> Result<(), Box<dyn std::error::Error>> {
   205→        // No special handling for healing events
   206→        Ok(())
   207→    }
   208→    
   209→    fn on_body_damage_state_change(
   210→        &mut self,
   211→        _damage_info: &DamageInfo,
   212→        old_state: u32,
   213→        new_state: u32,
   214→    ) -> Result<(), Box<dyn std::error::Error>> {
   215→        if new_state == BODY_REALLYDAMAGED {
   216→            self.start_crippled_effects()?;
   217→        } else if old_state == BODY_REALLYDAMAGED && new_state != BODY_REALLYDAMAGED {
   218→            self.stop_crippled_effects()?;
   219→        }
   220→        
   221→        Ok(())
   222→    }
   223→}
   224→
   225→impl BehaviorModuleInterface for SupplyWarehouseCripplingBehavior {
   226→    fn get_interface_mask() -> u32 {
   227→        MODULEINTERFACE_UPDATE | MODULEINTERFACE_DAMAGE
   228→    }
   229→    
   230→    fn get_update(&self) -> Option<&dyn UpdateModuleInterface> {
   231→        Some(self)
   232→    }
   233→    
   234→    fn get_damage(&self) -> Option<&dyn DamageModuleInterface> {
   235→        Some(self)
   236→    }
   237→}
   238→
   239→// Thread safety
   240→unsafe impl Send for SupplyWarehouseCripplingBehavior {}
   241→unsafe impl Sync for SupplyWarehouseCripplingBehavior {}
