   186→    
   187→    pub fn new(thing: Arc<RwLock<dyn Thing>>, module_data: Arc<dyn ModuleData>) -> Result<Self, Box<dyn std::error::Error>> {
   188→        let data = module_data.as_any()
   189→            .downcast_ref::<SlowDeathBehaviorModuleData>()
   190→            .ok_or("Invalid module data type")?;
   191→        
   192→        if data.probability_modifier < 1 {
   193→            return Err("ProbabilityModifier must be >= 1".into());
   194→        }
   195→        
   196→        Ok(Self {
   197→            object: None, // Will be set after creation
   198→            module_data: Arc::new(data.clone()),
   199→            flags: 0,
   200→            sink_frame: 0,
   201→            midpoint_frame: 0,
   202→            destruction_frame: 0,
