   211→    fn get_object(&self) -> Result<Arc<RwLock<Object>>, Box<dyn std::error::Error>> {
   212→        self.object.clone().ok_or("Object not set".into())
   213→    }
   214→    
   215→    fn is_slow_death_activated(&self) -> bool {
   216→        (self.flags & (1 << Self::SLOW_DEATH_ACTIVATED)) != 0
   217→    }
