   223→    fn do_phase_stuff(&mut self, phase: SlowDeathPhaseType) -> Result<(), Box<dyn std::error::Error>> {
   224→        let data = &self.module_data;
   225→        
   226→        if data.mask_of_loaded_effects == 0 {
   227→            return Ok(()); // No effects to process
   228→        }
   229→        
   230→        let phase_index = phase.to_index();
   231→        let object = self.get_object()?;
   232→        
   233→        // Handle FX
   234→        let fx_list = &data.fx[phase_index];
   235→        if !fx_list.is_empty() {
   236→            let idx = GameLogicRandomValue(0, fx_list.len() as Int - 1) as usize;
   237→            if let Some(fx) = fx_list.get(idx) {
   238→                FXList::do_fx_obj(fx, &object, None)?;
   239→            }
   240→        }
   241→        
   242→        // Handle OCLs (Object Creation Lists)
   243→        let ocl_list = &data.ocls[phase_index];
   244→        if !ocl_list.is_empty() {
   245→            let idx = GameLogicRandomValue(0, ocl_list.len() as Int - 1) as usize;
   246→            if let Some(ocl) = ocl_list.get(idx) {
   247→                ObjectCreationList::create(ocl, &object, None)?;
   248→            }
   249→        }
   250→        
   251→        // Handle weapons
   252→        let weapon_list = &data.weapons[phase_index];
   253→        if !weapon_list.is_empty() {
   254→            let idx = GameLogicRandomValue(0, weapon_list.len() as Int - 1) as usize;
   255→            if let Some(weapon) = weapon_list.get(idx) {
   256→                let obj_guard = object.read().map_err(|_| "Failed to read object")?;
   257→                let position = obj_guard.get_position();
   258→                drop(obj_guard);
   259→                TheWeaponStore::create_and_fire_temp_weapon(weapon, &object, &position)?;
   260→            }
   261→        }
   262→        
   263→        Ok(())
   264→    }
