   266→    /// Calculate random force for flinging objects
   267→    fn calc_random_force(min_mag: Real, max_mag: Real, min_pitch: Real, max_pitch: Real) -> Coord3D {
   268→        let angle = GameLogicRandomValueReal(-PI, PI);
   269→        let pitch = GameLogicRandomValueReal(min_pitch, max_pitch);
   270→        let magnitude = GameLogicRandomValueReal(min_mag, max_mag);
   271→        
   272→        let mut matrix = Matrix3D::identity();
   273→        matrix.scale(magnitude);
   274→        matrix.rotate_z(angle);
   275→        matrix.rotate_y(-pitch);
   276→        
   277→        let vector = matrix.get_x_vector();
   278→        
   279→        Coord3D::new(
   280→            vector.coords[0],
   281→            vector.coords[1],
   282→            vector.coords[2],
   283→        )
   284→    }
   285→}
