   287→impl UpdateModuleInterface for SlowDeathBehavior {
   288→    fn update(&mut self) -> Result<(), Box<dyn std::error::Error>> {
   289→        if !self.is_slow_death_activated() {
   290→            return Err("SlowDeathBehavior update called but not activated".into());
   291→        }
   292→        
   293→        let data = &self.module_data;
   294→        let object = self.get_object()?;
   295→        
   296→        let time_scale = TheGameLODManager::get_slow_death_scale();
   297→        
   298→        if time_scale != 1.0 && self.accelerated_time_scale == 1.0 && !data.has_non_lod_effects() {
   299→            if time_scale == 0.0 {
   300→                TheGameLogic::destroy_object(&object)?;
   301→                return Ok(());
   302→            }
   303→            
   304→            self.sink_frame = (self.sink_frame as Real * time_scale) as UnsignedInt;
   305→            self.midpoint_frame = (self.midpoint_frame as Real * time_scale) as UnsignedInt;
   306→            self.destruction_frame = (self.destruction_frame as Real * time_scale) as UnsignedInt;
   307→            self.accelerated_time_scale = time_scale;
   308→        }
   309→        
   310→        let now = TheGameLogic::get_frame();
   311→        
   312→        if now >= self.sink_frame && data.sink_rate > 0.0 {
   313→            let mut obj_guard = object.write().map_err(|_| "Failed to write object")?;
   314→            obj_guard.set_disabled(DISABLED_HELD)?;
   315→            
   316→            let mut pos = obj_guard.get_position().clone();
   317→            pos.z -= data.sink_rate / self.accelerated_time_scale;
   318→            obj_guard.set_position(&pos)?;
   319→            drop(obj_guard);
   320→        }
   321→        
   322→        if now >= self.midpoint_frame && (self.flags & (1 << Self::MIDPOINT_EXECUTED)) == 0 {
   323→            self.do_phase_stuff(SlowDeathPhaseType::Midpoint)?;
   324→            self.flags |= 1 << Self::MIDPOINT_EXECUTED;
   325→        }
   326→        
   327→        if now >= self.destruction_frame {
   328→            self.do_phase_stuff(SlowDeathPhaseType::Final)?;
   329→            TheGameLogic::destroy_object(&object)?;
   330→        }
   331→        
   332→        Ok(())
   333→    }
